#include <stdio.h>
#include <math.h>

static long long digit_sum(long long n, long long b){
    long long s = 0;
    while(n){ s += n % b; n /= b; }
    return s;
}

int main(){
    int Q; if(scanf("%d", &Q)!=1) return 0;
    while(Q--){
        long long n, r; scanf("%lld %lld", &n, &r);
        long long bestB = 2;
        long long best = digit_sum(n, 2);
        long long limit = (long long)sqrt((double)n);
        long long up = r < limit ? r : limit;
        for(long long B=2; B<=up; ++B){
            long long cur = digit_sum(n, B);
            if(cur < best){ best = cur; bestB = B; }
        }
        for(long long q=1; q<=limit; ++q){
            long long B = n / q;
            if(B < 2 || B > r) continue;
            long long cur = q + (n - q*B);
            if(cur < best){ best = cur; bestB = B; }
        }
        if(r > limit){
            long long cur = digit_sum(n, r);
            if(cur < best){ best = cur; bestB = r; }
        }
        printf("%lld\n", bestB);
    }
    return 0;
}

