import sys, math

def digit_sum(n, b):
    s = 0
    while n:
        s += n % b
        n //= b
    return s

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    Q = int(next(it))
    out = []
    for _ in range(Q):
        n = int(next(it)); r = int(next(it))
        bestB = 2
        best = digit_sum(n, 2)
        limit = int(math.isqrt(n))
        up = min(r, limit)
        for B in range(2, up+1):
            cur = digit_sum(n, B)
            if cur < best:
                best = cur; bestB = B
        for q in range(1, limit+1):
            B = n // q
            if B < 2 or B > r:
                continue
            cur = q + (n - q*B)
            if cur < best:
                best = cur; bestB = B
        if r > limit:
            cur = digit_sum(n, r)
            if cur < best:
                best = cur; bestB = r
        out.append(str(bestB))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

